#include <bits/stdc++.h>
#define int long long
using namespace std;
const int p = 20040313;
int inv[10000005], sum, n;
signed main () {
	ios::sync_with_stdio (0);
	cin.tie (0), cout.tie (0);
	cin >> n;
	inv[1] = 1;
	sum += 1;
	for (int i = 2; i <= n; i++) {
		inv[i] = (1ll * (p - p / i) * inv[p % i]) % p;
		sum = (sum + inv[i]) % p;
	}
	cout << n * sum % p;
	return 0; 
}
